1	type Cell = [number, number];
2	
3	const isNeighbor = ([x, y]: Cell, [otherX, otherY]: Cell): boolean =>
4	  (x !== otherX || y !== otherY) &&
5	  Math.abs(otherX - x) <= 1 &&
6	  Math.abs(otherY - y) <= 1;
7	
8	const countLiveNeighbors = (cell: Cell, livingCells: Cell[]): number =>
9	  livingCells.filter((other) => isNeighbor(cell, other)).length;
10	
11	const survives = (neighborCount: number): boolean =>
12	  neighborCount === 2 || neighborCount === 3;
13	
14	const reproduces = (neighborCount: number): boolean => neighborCount === 3;
15	
16	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
17	
18	const neighborsOf = ([x, y]: Cell): Cell[] => {
19	  const result: Cell[] = [];
20	  for (let dx = -1; dx <= 1; dx++) {
21	    for (let dy = -1; dy <= 1; dy++) {
22	      if (dx !== 0 || dy !== 0) result.push([x + dx, y + dy]);
23	    }
24	  }
25	  return result;
26	};
27	
28	const uniqueDeadNeighbors = (livingCells: Cell[]): Cell[] => {
29	  const liveKeys = new Set(livingCells.map(cellKey));
30	  const deadNeighbors = new Map<string, Cell>();
31	  for (const cell of livingCells) {
32	    for (const neighbor of neighborsOf(cell)) {
33	      const key = cellKey(neighbor);
34	      if (!liveKeys.has(key)) deadNeighbors.set(key, neighbor);
35	    }
36	  }
37	  return [...deadNeighbors.values()];
38	};
39	
40	export function nextGeneration(cells: Cell[]): Cell[] {
41	  const survivors = cells.filter((cell) =>
42	    survives(countLiveNeighbors(cell, cells)),
43	  );
44	  const births = uniqueDeadNeighbors(cells).filter((cell) =>
45	    reproduces(countLiveNeighbors(cell, cells)),
46	  );
47	  return [...survivors, ...births];
48	}
